import hashlib
import json
from pathlib import Path


def text_hash(text: str) -> str:
    return hashlib.sha256(text.encode()).hexdigest()


class EmbeddingCache:
    def __init__(self, path: str = ".embedding_cache.jsonl"):
        self.path = Path(path)
        self._cache: dict[str, list[float]] = {}
        if self.path.exists():
            for line in self.path.read_text().splitlines():
                entry = json.loads(line)
                self._cache[entry["key"]] = entry["vec"]

    def get(self, text: str) -> list[float] | None:
        return self._cache.get(text_hash(text))

    def set(self, text: str, vec: list[float]) -> None:
        key = text_hash(text)
        self._cache[key] = vec
        with self.path.open("a") as f:
            f.write(json.dumps({"key": key, "vec": vec}) + "\n")


cache = EmbeddingCache()


def embed_with_cache(
    texts: list[str], model: str = "text-embedding-3-small"
) -> list[list[float]]:
    hits: list[list[float] | None] = [cache.get(t) for t in texts]
    missing_indices = [i for i, h in enumerate(hits) if h is None]

    if missing_indices:
        missing_texts = [texts[i] for i in missing_indices]
        new_vecs = embed_openai(missing_texts, model)
        for i, vec in zip(missing_indices, new_vecs):
            cache.set(texts[i], vec)
            hits[i] = vec

    return hits  # type: ignore[return-value]
